            "string",
            "null"
          ]
        },
        "job_file": {
          "type": [
            "string",
            "null"
          ]
        },
        "output_schema_path": {
          "type": "string"
        },
        "output_path": {
          "type": "string"
        },
        "jsonl_log_path": {
          "type": "string"
        },
        "sandbox": {
          "type": "string",
          "enum": [
            "read-only",
            "workspace-write",
            "danger-full-access",
            "not_applicable"
          ]
        },
        "approval_policy": {
          "type": "string",
          "enum": [
            "never",
            "on-request",
            "untrusted",
            "not_applicable"
          ]
        }
      }
    },
    "inputs": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "input_type",
          "reference",
          "summary"
        ],
        "properties": {
          "input_type": {
            "type": "string",
            "enum": [
              "user_request",
              "plan_item",
              "coverage_gap",
              "candidate_change",
              "source_snapshot",
              "text_snapshot",
              "record",
              "export",
              "other"
            ]
          },
          "reference": {
            "type": "string"
          },
          "summary": {
            "type": "string"
          }
        }
      }
    },
    "outputs": {
      "anyOf": [
        {
          "type": "object",
